-- ============================================
-- MASIVO: Import all courses from JSON data
-- Run in Supabase SQL Editor
-- Includes: ciencias, administracion, ciencias_salud
-- Plus: ingenieria, tecnologia, humanidades, derecho,
--        educacion, artes, general, ciencias_sociales
-- ============================================

-- Step 1: Ensure all columns exist
ALTER TABLE opportunities ADD COLUMN IF NOT EXISTS course_level TEXT DEFAULT NULL;
ALTER TABLE opportunities ADD COLUMN IF NOT EXISTS course_duration TEXT DEFAULT NULL;
ALTER TABLE opportunities ADD COLUMN IF NOT EXISTS course_subject TEXT DEFAULT NULL;
ALTER TABLE opportunities ADD COLUMN IF NOT EXISTS course_language TEXT DEFAULT NULL;
ALTER TABLE opportunities ADD COLUMN IF NOT EXISTS educational_level TEXT DEFAULT 'universidad';
ALTER TABLE opportunities ADD COLUMN IF NOT EXISTS educational_field TEXT DEFAULT 'general';

CREATE INDEX IF NOT EXISTS idx_opportunities_course_level ON opportunities(course_level);
CREATE INDEX IF NOT EXISTS idx_opportunities_course_subject ON opportunities(course_subject);
CREATE INDEX IF NOT EXISTS idx_opportunities_course_language ON opportunities(course_language);
CREATE INDEX IF NOT EXISTS idx_opportunities_edu_level ON opportunities(educational_level);
CREATE INDEX IF NOT EXISTS idx_opportunities_edu_field ON opportunities(educational_field);

COMMENT ON COLUMN opportunities.course_level IS 'Difficulty: beginner, intermediate, advanced';
COMMENT ON COLUMN opportunities.course_duration IS 'Course length';
COMMENT ON COLUMN opportunities.course_subject IS 'Subject category';
COMMENT ON COLUMN opportunities.course_language IS 'Course language: en, es';

-- Step 2: Clear existing courses
DELETE FROM opportunities WHERE type = 'course';

